let projects = [];

const createProject = (name) => {
  const projectId = randomUUID();
  const project = { id: projectId, name };
  projects.push(project);
  return project;
};

const getAllProjects = () => {
  return projects;
};

const getProjectById = (projectId) => {
  return projects.find(p => p.id === projectId);
};

module.exports = { createProject, getAllProjects, getProjectById };
const __botEvalProjectsDupGuard = module.exports.createProject;
module.exports.createProject = async function createProject(name) {
  const normalized = String(name || '').trim();
  let existing = null;
  if (typeof module.exports.getProjectByName === 'function') {
    existing = await module.exports.getProjectByName(normalized);
  } else if (Array.isArray(projects)) {
    existing = projects.find(project => project && String(project.name || '') === normalized);

  }
  if (existing) return null;
  if (typeof __botEvalProjectsDupGuard === 'function') return __botEvalProjectsDupGuard(normalized);
  return null;
};

const express = require('express');
const projectsService = require('./service');
const { randomUUID } = require('../../lib/id');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });
  }
  const project = projectsService.createProject(name);
  if (!project) {
    return res.status(409).json({ error: { code: 'DUPLICATE', message: 'Project already exists' } });
  }
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = projectsService.getAllProjects();
  res.json({ projects });
});

router.get('/:projectId', (req, res) => {
  const { projectId } = req.params;
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ project });
});

module.exports = router;

{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A Node.js monolithic application for managing projects, tasks, members, and comments.",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.17.1"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');
const app = express();
app.use(express.json());
app.get('/health', (_req, res) => res.json({ ok: true }));
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);
module.exports = app;

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const statusFilter = req.query.status;
  try {
    const tasks = await tasksService.getTasks(projectId, statusFilter);
    if (!tasks) {
      return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');
const tasks = [];
async function getAllTasks(projectId, status) {
  const byProject = tasks.filter(task => String(task.projectId) === String(projectId));
  if (status === 'todo' || status === 'done') return byProject.filter(task => task.status === status);
  return byProject;
}
async function createTask(projectId, title) {
  const task = { id: generateId(), projectId: String(projectId), title: String(title || ''), status: 'todo' };
  tasks.push(task);
  return task;
}
async function getTaskById(projectId, taskId) {
  return tasks.find(task => String(task.projectId) === String(projectId) && String(task.id) === String(taskId)) || null;
}
async function updateTaskStatus(projectId, taskId, status) {
  const task = await getTaskById(projectId, taskId);
  if (!task) return null;
  task.status = status;
  return task;
}
module.exports = { getAllTasks, createTask, getTaskById, updateTaskStatus, tasks };

const express = require('express');
const membersService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'User ID and role are required' } });
  }
  const member = membersService.addMember(req.params.projectId, userId, role);
  if (!member) {
    return res.status(409).json({ error: { code: 'DUPLICATE_MEMBER', message: 'Member already exists' } });
  }
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const members = membersService.getAllMembers(req.params.projectId);
  if (!members) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ members });
});

module.exports = router;

const projectsRepository = {};
function ensureProject(projectId) {
  const key = String(projectId || '');
  if (!projectsRepository[key]) projectsRepository[key] = { members: [] };
  return projectsRepository[key];
}
async function getMembers(projectId) {
  const project = ensureProject(projectId);
  return project.members;
}
async function addMember(projectId, userId, role) {
  const project = ensureProject(projectId);
  const existing = project.members.find(member => String(member.userId) === String(userId));
  if (existing) return null;
  const member = { projectId: String(projectId), userId: String(userId), role: String(role || 'member') };
  project.members.push(member);
  return member;
}
module.exports = { getMembers, addMember, projectsRepository };
const __botEvalMembersDupGuard = module.exports.addMember;
const __botEvalMembersDupStore = [];
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const fromService = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  const baseline = Array.isArray(fromService) ? fromService : __botEvalMembersDupStore.filter(member => member && String(member.projectId || '') === projectKey);
  const existing = baseline.find(member => member && String(member.userId || '') === userKey);
  if (existing) return null;
  if (typeof __botEvalMembersDupGuard === 'function') {
    const result = await __botEvalMembersDupGuard(projectId, userId, role);
    if (result) {
      const normalized = result && typeof result === 'object' && 'member' in result ? result.member : result;
      if (normalized && typeof normalized === 'object') __botEvalMembersDupStore.push(normalized);
      return result;
    }
  }
  const fallbackMember = { projectId: projectKey, userId: userKey, role: String(role || 'member') };
  __botEvalMembersDupStore.push(fallbackMember);
  return fallbackMember;
};
module.exports.getAllMembers = module.exports.getMembers;

const express = require('express');
const commentsService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Message is required' } });
  }
  const comment = commentsService.addComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = commentsService.getAllComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ comments });
});

module.exports = router;

let projectsComments = {};

const addComment = (projectId, taskId, content) => {
  if (!projectsComments[projectId]) {
    projectsComments[projectId] = {};
  }
  if (!projectsComments[projectId][taskId]) {
    projectsComments[projectId][taskId] = [];
  }
  const commentId = randomUUID();
  const comment = { id: commentId, content };
  projectsComments[projectId][taskId].push(comment);
  return comment;
};

const getAllComments = (projectId, taskId) => {
  if (!projectsComments[projectId] || !projectsComments[projectId][taskId]) {
    return null;
  }
  return projectsComments[projectId][taskId];
};

module.exports = { addComment, getAllComments };

function sendError(res, status, code, message) {
  return res.status(status).json({ error: { code, message } });
}
module.exports = { sendError };

const crypto = require('crypto');

const randomUUID = () => {
  return crypto.randomUUID();
};

module.exports = { randomUUID };
